{
    "query": "{ games { totalCount hasNextPage games { id title } } }"
}

{
    "query": "{ games(limit: 10) { totalCount hasNextPage games { id title } } }"
}

{
    "query": "{ games(limit: 10, offset: 1) { totalCount hasNextPage games { id title } } }"
}

{
    "query": "{ games(title: \"Zelda\") { totalCount hasNextPage games { id title } } }"
}

{
    "query": "{ games(minMetascore: 95) { totalCount hasNextPage games { id title metascore } } }"
}

{
    "query": "mutation UpdateGame($updateGameId: Int!, $title: String) { updateGame(id: $updateGameId, title: $title) { id title } }",
    "variables": {
        "updateGameId": {{createdGameId}},
        "title": "Plupp 2"
    }
}

{
    "query": "mutation CreateUser($username: String!, $email: String!, $password: String!) { createUser(username: $username, email: $email, password: $password) { token user { id email } } }",
    "variables": {
        "username": "Tove",
        "password": "test",
        "email": "Oak@test.se"
    }
}

{
    "query": "mutation CreateUser($username: String!, $email: String!, $password: String!) { createUser(username: $username, email: $email, password: $password) { token user { id email } } }",
    "variables": {
        "username": "testuser_{{$timestamp}}",
        "password": "test",
        "email": "test_{{$timestamp}}@test.com"
    }
}

{
    "query": "mutation LoginUser($email: String!, $password: String!) { loginUser(email: $email, password: $password) { token user { id email } } }",
